  "backend/src/main/java/com/hwscs/backend/dto/response/LoginResponseDto.java": "package com.hwscs.backend.dto.response;\r\n\r\npublic class LoginResponseDto {\r\n\r\n    private String token;\r\n    private String username;\r\n    private String role;\r\n    private Long userId;\r\n    private Boolean firstLogin;\r\n    private String fullName;\r\n\r\n    public LoginResponseDto(String token, String username, String role, Long userId, Boolean firstLogin) {\r\n        super();\r\n        this.token = token;\r\n        this.username = username;\r\n        this.role = role;\r\n        this.userId = userId;\r\n        this.firstLogin = firstLogin;\r\n    }\r\n\r\n    public LoginResponseDto() {\r\n    }\r\n\r\n    // Private constructor for Builder\r\n    private LoginResponseDto(Builder builder) {\r\n        this.token = builder.token;\r\n        this.username = builder.username;\r\n        this.role = builder.role;\r\n        this.userId = builder.userId;\r\n        this.firstLogin = builder.firstLogin;\r\n        this.fullName = builder.fullName;\r\n    }\r\n\r\n    // Manual builder() method\r\n    public static Builder builder() {\r\n        return new Builder();\r\n    }\r\n\r\n    public String getToken() {\r\n        return token;\r\n    }\r\n\r\n    public void setToken(String token) {\r\n        this.token = token;\r\n    }\r\n\r\n    public String getUsername() {\r\n        return username;\r\n    }\r\n\r\n    public void setUsername(String username) {\r\n        this.username = username;\r\n    }\r\n\r\n    public String getRole() {\r\n        return role;\r\n    }\r\n\r\n    public void setRole(String role) {\r\n        this.role = role;\r\n    }\r\n\r\n    public Long getUserId() {\r\n        return userId;\r\n    }\r\n\r\n    public void setUserId(Long userId) {\r\n        this.userId = userId;\r\n    }\r\n\r\n    public Boolean getFirstLogin() {\r\n        return firstLogin;\r\n    }\r\n\r\n    public void setFirstLogin(Boolean firstLogin) {\r\n        this.firstLogin = firstLogin;\r\n    }\r\n\r\n    public String getFullName() {\r\n        return fullName;\r\n    }\r\n\r\n    public void setFullName(String fullName) {\r\n        this.fullName = fullName;\r\n    }\r\n\r\n    // Builder implementation\r\n    public static class Builder {\r\n        private String token;\r\n        private String username;\r\n        private String role;\r\n        private Long userId;\r\n        private Boolean firstLogin;\r\n        private String fullName;\r\n\r\n        public Builder token(String token) {\r\n            this.token = token;\r\n            return this;\r\n        }\r\n\r\n        public Builder username(String username) {\r\n            this.username = username;\r\n            return this;\r\n        }\r\n\r\n        public Builder role(String role) {\r\n            this.role = role;\r\n            return this;\r\n        }\r\n\r\n        public Builder userId(Long userId) {\r\n            this.userId = userId;\r\n            return this;\r\n        }\r\n\r\n        public Builder firstLogin(Boolean firstLogin) {\r\n            this.firstLogin = firstLogin;\r\n            return this;\r\n        }\r\n\r\n        public Builder fullName(String fullName) {\r\n            this.fullName = fullName;\r\n            return this;\r\n        }\r\n\r\n        public LoginResponseDto build() {\r\n            return new LoginResponseDto(this);\r\n        }\r\n    }\r\n}",
